func InitGlobalLogger(level logg.Level, panicOnWarnings bool) {
	logMu.Lock()
	defer logMu.Unlock()
	var logHookLast func(e *logg.Entry) error
	if panicOnWarnings {
		logHookLast = PanicOnWarningHook
	}

	log = New(
		Options{
			Level:		level,
			DistinctLevel:	logg.LevelInfo,
			HandlerPost:	logHookLast,
		},
	)
}
